  "plan": "Create `/app/work/combined_extractor.py` that (1) parses 1fps OCR move-count anchors and prompt histories, (2) parses 5fps bottom OCR active prompt/input lines, (3) applies OCR corrections, (4) builds an interval command list with repeated moves preserved, (5) writes `/app/work/logs/combined_candidates.log`, and (6) reports whether the count is exactly 262. This is an intermediate validation step; it will not write `/app/solution.txt` until the candidate list is validated.",
  "commands": [
    {
      "keystrokes": "cat > /app/work/combined_extractor.py <<'PY'
import glob, os, re
from collections import defaultdict

# Files
ocr1=sorted(glob.glob('/app/work/ocr/frame_*.txt'), key=lambda p:int(os.path.basename(p).split('_')[1].split('.')[0]))
bottom5=sorted(glob.glob('/app/work/bottom5/frame_*.txt'), key=lambda p:int(os.path.basename(p).split('_')[1].split('.')[0]))

# OCR corrections
fixes = {
    'n.':'n', 'gY':'y', 'Y':'y', 'G':'again', 'g':'again',
    'move,':'move rug', 'open tra':'open trap',
    'ulysse':'ulysses', 'ulyss':'ulysses',
    'pu,':'put', 'pu':'put',
    'Dopen':'open', 'dopen':'open',
    'elose':'close',
    'eage':'cage', 'ceage':'cage', 'ca_':'cage', 'ca':'cage',
    'mirro':'mirror',
    'temp':'temple', 'tem':'temple', 'tem_':'temple',
    'rin':'ring', 'dro':'drop',
    'get all fr':'get all from cage', 'get all from _':'get all from cage', 'get all from ca_':'get all from cage',
    'get lamp,clove':'get lamp,clove,screwdriver', 'get lamp,clove,sc':'get lamp,clove,screwdriver', 'get lamp,clove,screw':'get lamp,clove,screwdriver',
    'put torch,scr':'put torch,screwdriver', 'put torch,screw':'put torch,screwdriver',
    'get huge, tor':'get huge,torch', 'get huge,torc':'get huge,torch', 'get nuge,torcn':'get huge,torch', 'get huge,tor':'get huge,torch',
    'get egg,sow':'get egg,sword,lamp', 'get egg, sword,1':'get egg,sword,lamp',
    'get head, jade,cup,egg,go':'get head,jade,cup,egg,golden',
    'get head, jade,cup,egg, golden':'get head,jade,cup,egg,golden',
    'get head, jade,cup,egg,gold':'get head,jade,cup,egg,golden',
    'get head, Jade ,cup,egg,goiden':'get head,jade,cup,egg,golden',
    'Wind ac':'wind canary', 'Wind canary':'wind canary', 'win':'wind canary', 'win_':'wind canary',
    '1li':'li', '1lid':'lid', 'Lid':'lid', 'lid':'lid',
    'wW':'w',
    'put all':'put all in case',
    'case':'case',
    'e,':'e',
    'd.':'d',
    'ne.':'ne',
}

def fix_cmd(s):
    s=s.strip().rstrip('._').strip()
    s=re.sub(r'\s+',' ',s).strip()
    return fixes.get(s,s)

def clean_prompt_line(s):
    s=s.strip()
    if not s.startswith('>'):
        return ''
    s=s[1:].strip().rstrip('._').strip()
    s=re.sub(r'\s+',' ',s).strip()
    if not s:
        return ''
    return fix_cmd(s)

def norm_bottom(s):
    s=re.sub(r'[^A-Za-z0-9>, ._]', ' ', s)
    s=re.sub(r'\s+', ' ', s).strip()
    if s.startswith('>'):
        s=s[1:].strip()
    return fix_cmd(s)

# Parse 1fps frames with move counts and prompt histories
frames=[]
for idx,p in enumerate(ocr1,1):
    txt=open(p,errors='ignore').read()
    m=re.search(r'Moves?:\s*(\d+)', txt)
    mv=int(m.group(1)) if m else None
    prompts=[]
    for line in txt.splitlines():
        c=clean_prompt_line(line)
        if c:
            prompts.append(c)
    frames.append({'idx':idx,'mv':mv,'prompts':prompts})

# Move-count anchors
anchors=[(i,frames[i]['mv']) for i in range(len(frames)) if frames[i]['mv'] is not None]

# Dense bottom5 lines (frame index at 5fps)
b5=[]
for idx,p in enumerate(bottom5,1):
    raw=open(p,errors='ignore').read().strip()
    b5.append(norm_bottom(raw))

# Detect dense submit groups: non-empty prompt continuation followed by blank or new root.
dense=[]
cur=None
for i,line in enumerate(b5,1):
    if line:
        if cur is None:
            cur=(i,line)
        else:
            if line.startswith(cur[1]) or (len(cur[1])>=3 and line.startswith(cur[1][:-1])):
                cur=(i,line)
            elif cur[1].startswith(line) and len(cur[1])-len(line) <= 3:
                pass
            else:
                dense.append(cur)
                cur=(i,line)
    else:
        if cur:
            dense.append(cur)
            cur=None
if cur:
    dense.append(cur)

# Map dense 5fps frame index to 1fps frame index (1fps frame n corresponds roughly 5fps frames 5n-4..5n)
def b5_to_1fps(i):
    return max(1, min(len(frames), (i+4)//5))

# Build interval commands from move-count anchors and 1fps prompt history.
cands=[]
if anchors:
    prev_i, prev_mv = 0, 0
    for end_i, end_mv in anchors:
        delta = end_mv - prev_mv
        if delta <= 0:
            continue
        interval=[]
        for j in range(prev_i, end_i+1):
            for p in frames[j]['prompts']:
                interval.append((frames[j]['idx'], p))
        # Collapse typing continuations but preserve distinct root commands/repeats.
        collapsed=[]
        for j,p in interval:
            if collapsed and (p.startswith(collapsed[-1][1]) or collapsed[-1][1].startswith(p)):
                if len(p) >= len(collapsed[-1][1]):
                    collapsed[-1]=(j,p)
            else:
                collapsed.append((j,p))
        # Remove pure prefixes that are substrings of later commands, but keep repeats.
        kept=[]
        for n,(j,p) in enumerate(collapsed):
            is_prefix=False
            for jj,pp in collapsed[n+1:]:
                if pp.startswith(p) and len(pp) > len(p):
                    is_prefix=True
                    break
            if not is_prefix:
                kept.append((j,p))
        # Take last delta items if available; otherwise take all.
        if delta <= len(kept):
            chosen = kept[-delta:]
        else:
            chosen = kept
        for j,p in chosen:
            cands.append((j,p))
        prev_i, prev_mv = end_i, end_mv
else:
    # Fallback to dense submit groups
    cands = [(b5_to_1fps(i), p) for i,p in dense]

# Deduplicate consecutive identical only (allow repeats separated by other commands).
final=[]
for idx,p in cands:
    if final and final[-1][1] == p:
        continue
    if final and p.startswith(final[-1][1]):
        continue
    final.append((idx,p))

with open('/app/work/logs/combined_candidates.log','w') as f:
    for n,(idx,cmd) in enumerate(final,1):
        f.write(f'{n:03d} f{idx:03d} {cmd}\n')

print('combined_count', len(final))
print('expected_count', 262)
print('match', len(final) == 262)
print('first20', final[:20])
print('last20', final[-20:])
